class StockSpanner {

    public StockSpanner() {

    }

    public int next(int price) {
        int res = 1;
        while (!stack.isEmpty() && stack.peek() <= price) {
            stack.pop();
            res += 1;
        }
        stack.push(price);
        return res;
    }
    private Stack<Integer> stack = new Stack<>();
}
```
